    const tabButtons = document.querySelectorAll('.tab-button');
    const tabPanels = document.querySelectorAll('.tab-panel');

    tabButtons.forEach(button => {
      button.addEventListener('click', () => {
        const tab = button.dataset.tab;
        tabButtons.forEach(btn => btn.classList.toggle('active', btn === button));
        tabPanels.forEach(panel => panel.classList.toggle('active', panel.id === `tab-${tab}`));
      });
    });

    const tableBody = document.getElementById('oemTableBody');
    const searchInput = document.getElementById('searchInput');
    const categoryFilter = document.getElementById('categoryFilter');
    const alibabaFilter = document.getElementById('alibabaFilter');
    const resultsLabel = document.getElementById('resultsLabel');
    const statVisible = document.getElementById('stat-visible');
    const downloadBtn = document.getElementById('downloadBtn');

    function normalize(value) {
      return (value || '').toString().trim();
    }

    function hasAlibaba(value) {
      const v = normalize(value).toLowerCase();
      return v !== '' && v !== 'n/a' && v !== 'na' && v !== '-';
    }

    function renderTable(rows) {
      if (!rows.length) {
        tableBody.innerHTML = `
          <tr>
            <td colspan="6" class="muted" style="padding: 22px;">Aucun résultat avec les filtres actuels.</td>
          </tr>
        `;
      } else {
        tableBody.innerHTML = rows.map(item => {
          const site = normalize(item['Site Web']);
          const alibaba = normalize(item['Alibaba']);
          const email = normalize(item['Mail']);
          const whatsapp = normalize(item['Whatsup']);
          return `
            <tr>
              <td>${normalize(item['Fabricant/Fournisseur'])}</td>
              <td><span class="pill">${normalize(item['Catégorie']) || '—'}</span></td>
              <td>${site && site.toLowerCase() !== 'n/a' ? `<a href="${site.startsWith('http') ? site : 'https://' + site}" target="_blank" rel="noopener noreferrer">Ouvrir</a>` : '<span class="muted">N/A</span>'}</td>
              <td>${hasAlibaba(alibaba) ? `<a href="${alibaba}" target="_blank" rel="noopener noreferrer"><span class="pill ok">Disponible</span></a>` : '<span class="muted">N/A</span>'}</td>
              <td>${email && email.toLowerCase() !== 'n/a' ? `<a href="mailto:${email}">${email}</a>` : '<span class="muted">N/A</span>'}</td>
              <td>${whatsapp ? `<a href="https://wa.me/${whatsapp.replace(/[^\d]/g, '')}" target="_blank" rel="noopener noreferrer">${whatsapp}</a>` : '<span class="muted">N/A</span>'}</td>
            </tr>
          `;
        }).join('');
      }

      resultsLabel.textContent = `${rows.length} résultat(s)`;
      statVisible.textContent = rows.length;
      window.filteredManufacturers = rows;
    }

    function applyFilters() {
      const q = normalize(searchInput.value).toLowerCase();
      const category = categoryFilter.value;
      const alibaba = alibabaFilter.value;

      const filtered = manufacturers.filter(item => {
        const haystack = Object.values(item).join(' ').toLowerCase();
        const matchesSearch = !q || haystack.includes(q);
        const matchesCategory = !category || normalize(item['Catégorie']) === category;
        const matchesAlibaba =
          !alibaba ||
          (alibaba === 'yes' && hasAlibaba(item['Alibaba'])) ||
          (alibaba === 'no' && !hasAlibaba(item['Alibaba']));
        return matchesSearch && matchesCategory && matchesAlibaba;
      });

      renderTable(filtered);
    }

    function downloadCSV(rows) {
      const headers = ['Fabricant/Fournisseur', 'Catégorie', 'Site Web', 'Alibaba', 'Mail', 'Whatsup'];
      const escapeCSV = (value) => `"${normalize(value).replace(/"/g, '""')}"`;
      const csv = [
        headers.join(','),
        ...rows.map(row => headers.map(h => escapeCSV(row[h])).join(','))
      ].join('\n');

      const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = 'fabricants-oem-odm-filtre.csv';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }

    searchInput.addEventListener('input', applyFilters);
    categoryFilter.addEventListener('change', applyFilters);
    alibabaFilter.addEventListener('change', applyFilters);
    downloadBtn.addEventListener('click', () => downloadCSV(window.filteredManufacturers || manufacturers));

    renderTable(manufacturers);
  


