    (function () {
      const modal = document.getElementById('pageImageModal');
      const modalImg = document.getElementById('pageImageView');
      const modalTitle = document.getElementById('pageImageTitle');
      const modalClose = document.getElementById('pageImageClose');

      function openPageImage(src, ref) {
        if (!src) return;
        modalImg.src = src;
        modalTitle.textContent = 'Page source · ' + ref;
        modal.classList.add('open');
        modal.setAttribute('aria-hidden', 'false');
      }

      function closePageImage() {
        modal.classList.remove('open');
        modal.setAttribute('aria-hidden', 'true');
        modalImg.src = '';
      }

      modalClose.addEventListener('click', closePageImage);

      modal.addEventListener('click', function (e) {
        if (e.target === modal) closePageImage();
      });

      document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape' && modal.classList.contains('open')) {
          closePageImage();
        }
      });

      document.addEventListener('click', function (e) {
        const trigger = e.target.closest('[data-action="page-image"]');
        if (!trigger) return;
        const src = trigger.getAttribute('data-fullpage');
        const ref = trigger.getAttribute('data-ref') || 'modèle';
        if (src) openPageImage(src, ref);
      });
    })();
  